import fs from 'fs'

const utilsProviderProfilesPath = 'src/commands/provider/provider.tsx'
let providerProfilesData = fs.readFileSync(utilsProviderProfilesPath, 'utf8')

// Assuming there's a list of options for provider. Let's find "openai" or "ollama" label.
if (!providerProfilesData.includes("value: 'qwen-oauth'")) {
    providerProfilesData = providerProfilesData.replace(
        /value: 'openai' \},/g,
        "value: 'openai' },\n      { label: 'Qwen OAuth', value: 'qwen-oauth', description: 'Authenticate via qwen_creds.json generated by Qwen Code' },"
    )
    providerProfilesData = providerProfilesData.replace(
      /\} else if \(value === 'openai'\) \{/,
      `} else if (value === 'qwen-oauth') {
        const env = {
          CLAUDE_CODE_USE_OPENAI: '1',
          OPENAI_BASE_URL: 'https://portal.qwen.ai/v1',
          OPENAI_MODEL: 'qwen2.5-coder',
          OPENAI_API_KEY: '',
        }
        onSave('qwen-oauth', env)
      } else if (value === 'openai') {`
    )
}

fs.writeFileSync(utilsProviderProfilesPath, providerProfilesData)
